#include <stdio.h>
#include <stdbool.h>

int main() {
    int N;
    scanf("%d", &N);
    int permutation[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &permutation[i]);
    }
    bool visited[N];
    for (int i = 0; i < N; i++) {
        visited[i] = false;
    }
    int cycleCount = 0;
    for (int i = 0; i < N; i++) {
        if (!visited[i]) {
            cycleCount++;
            printf("%d", i + 1);
            int current = permutation[i] - 1;
            while (current != i) {
                printf(" %d", current + 1);
                visited[current] = true;
                current = permutation[current] - 1;
            }
            printf(" %d\n", i + 1);
        }
    }
    printf("%d\n", cycleCount);
    return 0;
}

